#!/usr/bin/env dotnet-script
#r "nuget: Microsoft.Agents.AI, 1.5.0"
#r "nuget: Microsoft.Extensions.AI, 10.5.1"
#r "nuget: Microsoft.Extensions.AI.Abstractions, 10.5.2"

using System;
using System.Reflection;
using System.Linq;

var dlls = new[] {
    "Microsoft.Agents.AI",
    "Microsoft.Extensions.AI",
    "Microsoft.Extensions.AI.Abstractions"
};

foreach (var dllName in dlls)
{
    Console.WriteLine($"\n{'='*80}");
    Console.WriteLine($"Assembly: {dllName}");
    Console.WriteLine($"{'='*80}\n");

    try
    {
        var asm = AppDomain.CurrentDomain.GetAssemblies()
            .FirstOrDefault(a => a.GetName().Name == dllName);

        if (asm == null)
        {
            Console.WriteLine($"Could not load {dllName}");
            continue;
        }

        var types = asm.GetTypes()
            .Where(t => t.IsPublic)
            .OrderBy(t => t.Name);

        foreach (var type in types)
        {
            Console.WriteLine($"\nPUBLIC {(type.IsInterface ? "INTERFACE" : type.IsAbstract ? "ABSTRACT CLASS" : "CLASS")}: {type.FullName}");

            // Show methods
            var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                .Where(m => !m.IsSpecialName)
                .OrderBy(m => m.Name);

            if (methods.Any())
            {
                Console.WriteLine("  Methods:");
                foreach (var method in methods.Take(20))
                {
                    var returnType = method.ReturnType.Name;
                    var args = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"    • {method.Name}({args}): {returnType}");
                }
            }

            // Show properties
            var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                .OrderBy(p => p.Name);

            if (props.Any())
            {
                Console.WriteLine("  Properties:");
                foreach (var prop in props.Take(20))
                {
                    var getSet = $"{(prop.CanRead ? "get" : "")}{(prop.CanRead && prop.CanWrite ? ";" : "")}{(prop.CanWrite ? "set" : "")}";
                    Console.WriteLine($"    • {prop.PropertyType.Name} {prop.Name} {{ {getSet} }}");
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"Error: {ex.Message}");
    }
}
EOF
