using System;
using System.Reflection;
using System.Linq;
using System.Collections.Generic;

class Program
{
    static void Main()
    {
        var dllPaths = new[] {
            "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net8.0/Microsoft.Agents.AI.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net8.0/Microsoft.Extensions.AI.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.1/lib/net8.0/Microsoft.Extensions.AI.Abstractions.dll"
        };

        foreach (var dllPath in dllPaths)
        {
            Console.WriteLine($"\n{'='*100}");
            Console.WriteLine($"Loading: {new System.IO.FileInfo(dllPath).Name}");
            Console.WriteLine($"{'='*100}\n");

            try
            {
                var asm = Assembly.LoadFrom(dllPath);
                var types = asm.GetTypes()
                    .Where(t => t.IsPublic && t.Namespace != null)
                    .OrderBy(t => t.Namespace)
                    .ThenBy(t => t.Name);

                var byNamespace = types.GroupBy(t => t.Namespace);

                foreach (var nsGroup in byNamespace)
                {
                    Console.WriteLine($"\n📦 Namespace: {nsGroup.Key}");
                    Console.WriteLine("─" + new string('─', 98));

                    foreach (var type in nsGroup)
                    {
                        var typeKind = type.IsInterface ? "interface" : type.IsAbstract ? "abstract class" : type.IsEnum ? "enum" : "class";
                        Console.WriteLine($"\n  ┌─ {typeKind.ToUpper()}: {type.Name}");

                        // Base types
                        if (type.BaseType != null && type.BaseType != typeof(object) && type.BaseType != typeof(ValueType))
                        {
                            Console.WriteLine($"  │  └─ inherits: {type.BaseType.Name}");
                        }

                        // Interfaces
                        var interfaces = type.GetInterfaces().Where(i => i.Namespace?.StartsWith("Microsoft") == true).ToList();
                        if (interfaces.Any())
                        {
                            foreach (var iface in interfaces.Take(3))
                            {
                                Console.WriteLine($"  │  └─ implements: {iface.Name}");
                            }
                        }

                        // Methods
                        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                            .Where(m => !m.IsSpecialName && !m.IsPrivate)
                            .OrderBy(m => m.Name);

                        foreach (var method in methods.Take(10))
                        {
                            var args = string.Join(", ", method.GetParameters().Select(p => $"{GetTypeName(p.ParameterType)} {p.Name}"));
                            var isAsync = method.ReturnType.Name.Contains("Task") ? " [ASYNC]" : "";
                            Console.WriteLine($"  │  ├─ {method.Name}({args}): {GetTypeName(method.ReturnType)}{isAsync}");
                        }

                        // Properties
                        var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                            .OrderBy(p => p.Name);

                        foreach (var prop in props.Take(10))
                        {
                            var access = $"{(prop.CanRead ? "r" : "")}{(prop.CanWrite ? "w" : "")}";
                            Console.WriteLine($"  │  └─ {prop.Name}: {GetTypeName(prop.PropertyType)} [{access}]");
                        }

                        Console.WriteLine($"  └─");
                    }
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"ERROR: {ex.Message}");
                Console.WriteLine(ex.StackTrace);
            }
        }
    }

    static string GetTypeName(Type t)
    {
        if (t.IsGenericType)
        {
            var baseName = t.Name.Substring(0, t.Name.IndexOf('`'));
            var args = string.Join(", ", t.GetGenericArguments().Select(a => GetTypeName(a)));
            return $"{baseName}<{args}>";
        }
        return t.Name;
    }
}
EOF

