using System.Reflection;

var resolver = new MetadataLoadContext(
    new PathAssemblyResolver(new[] {
        Environment.GetEnvironmentVariable("AGENTS_DLL")!,
        Environment.GetEnvironmentVariable("AGENTS_ABS_DLL")!,
        Environment.GetEnvironmentVariable("MEAI_DLL")!,
        Environment.GetEnvironmentVariable("MEAI_ABS_DLL")!,
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Runtime.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Collections.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Threading.Tasks.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Linq.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "netstandard.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Private.CoreLib.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.ObjectModel.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.ComponentModel.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.ComponentModel.Primitives.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Text.Json.dll"),
        Path.Combine(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "System.Memory.dll"),
    }.Concat(Directory.GetFiles(System.Runtime.InteropServices.RuntimeEnvironment.GetRuntimeDirectory(), "*.dll"))));

void DumpTypes(string dllPath, string label) {
    var asm = resolver.LoadFromAssemblyPath(dllPath);
    Console.WriteLine($"\n=== {label} ===");
    foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName)) {
        Console.WriteLine($"\n  [{(t.IsClass ? "class" : t.IsInterface ? "interface" : t.IsEnum ? "enum" : "struct")}] {t.FullName}");
        if (t.BaseType != null && t.BaseType.FullName != "System.Object")
            Console.WriteLine($"    : {t.BaseType.FullName}");
        foreach (var iface in t.GetInterfaces())
            Console.WriteLine($"    implements {iface}");
        foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance)) {
            var parms = string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType} {p.Name}"));
            Console.WriteLine($"    ctor({parms})");
        }
        foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)) {
            Console.WriteLine($"    prop {p.PropertyType} {p.Name} {{ {(p.CanRead?"get;":"")}{(p.CanWrite?" set;":"")} }}");
