using System;
using System.IO;
using System.Reflection;
using System.Linq;

class Program
{
    static void Main()
    {
        var dllPaths = new[] {
            "/home/runner/.nuget/packages/microsoft.extensions.ai.abstractions/10.5.1/lib/net8.0/Microsoft.Extensions.AI.Abstractions.dll",
            "/home/runner/.nuget/packages/microsoft.extensions.ai/10.5.1/lib/net8.0/Microsoft.Extensions.AI.dll",
            "/home/runner/.nuget/packages/microsoft.agents.ai/1.5.0/lib/net8.0/Microsoft.Agents.AI.dll"
        };

        foreach (var dllPath in dllPaths.Where(File.Exists))
        {
            Console.WriteLine($"\n{'='*100}");
            Console.WriteLine($"Loading: {Path.GetFileName(dllPath)}");
            Console.WriteLine($"{'='*100}\n");

            try
            {
                // Load with all dependencies
                var asm = Assembly.LoadFrom(dllPath);
                var types = asm.GetTypes()
                    .Where(t => t.IsPublic && (t.Namespace?.Contains("Microsoft") == true))
                    .OrderBy(t => t.Namespace)
                    .ThenBy(t => t.Name);

                var byNamespace = types.GroupBy(t => t.Namespace);

                foreach (var nsGroup in byNamespace)
                {
                    Console.WriteLine($"\n📦 Namespace: {nsGroup.Key}");

                    foreach (var type in nsGroup)
                    {
                        var typeKind = type.IsInterface ? "interface" : 
                                      type.IsAbstract ? "abstract class" : 
                                      type.IsEnum ? "enum" : "class";

                        Console.WriteLine($"\n  {typeKind.ToUpper()}: {type.Name}");

                        // Show key methods and properties
                        var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                            .Where(m => !m.IsSpecialName)
                            .OrderBy(m => m.Name)
                            .Take(15);

                        foreach (var method in methods)
                        {
                            var args = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                            Console.WriteLine($"    + {method.Name}({args}): {method.ReturnType.Name}");
                        }

                        var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                            .OrderBy(p => p.Name);

                        foreach (var prop in props)
                        {
                            Console.WriteLine($"    @ {prop.Name}: {prop.PropertyType.Name}");
                        }
                    }
                }
            }
            catch (ReflectionTypeLoadException rex)
            {
                Console.WriteLine($"ReflectionTypeLoadException: {rex.Message}");
                if (rex.LoaderExceptions != null)
                {
                    foreach (var ex in rex.LoaderExceptions.Take(3))
                    {
                        Console.WriteLine($"  - {ex?.Message}");
                    }
                }
            }
            catch (Exception ex)
            {
                Console.WriteLine($"ERROR: {ex.Message}");
            }
        }
    }
}
