using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notepad = new Notepad();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(
        SearchWebAsync,
        "SearchWeb",
        "Searches the web for a query and returns a list of result snippets. " +
        "Use this to find information about a topic."),
    AIFunctionFactory.Create(
        notepad.AddNote,
        "AddNote",
        "Saves a note with a title and body. Use this to record key findings " +
        "during research so they can be referenced in the final summary."),
    AIFunctionFactory.Create(
        notepad.GetNotes,
        "GetNotes",
        "Returns all notes saved so far. Use this to review what has been " +
        "recorded before writing the final summary."),
};

// --- Agent -------------------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user gives you a topic:
        1. Search the web for relevant information (perform multiple searches
           with different queries to get broad coverage).
        2. As you find important facts, save them using the AddNote tool.
        3. After gathering enough information, review your notes with GetNotes.
        4. Produce a well-structured summary of your findings with sections,
           key points, and source attribution where possible.
        Be thorough but concise. Aim for 3-5 searches per topic.
        """,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and summarizing findings.",
    tools: tools);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

// --- Interactive loop --------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════════╗");
Console.WriteLine("║        AI Research Agent (GPT-4o-mini)   ║");
Console.WriteLine("║  Type a topic to research, or 'quit'.    ║");
Console.WriteLine("╚══════════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
    {
        Console.WriteLine("Goodbye!");
        break;
    }

    notepad.Clear();

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine($"\n  Researching: {topic}...\n");
    Console.ResetColor();

    try
    {
        var response = await agent.RunAsync(
            $"Please research the following topic thoroughly: {topic}",
            session: null,
            options: runOptions);

        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine("── Research Summary ─────────────────────────");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine("─────────────────────────────────────────────");

        if (notepad.Count > 0)
        {
            Console.ForegroundColor = ConsoleColor.DarkYellow;
            Console.WriteLine($"\n  [{notepad.Count} note(s) recorded during research]");
            Console.ResetColor();
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.Error.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

// --- Tool implementations ----------------------------------------------------

/// <summary>
/// Searches the web using DuckDuckGo's HTML endpoint (no API key required).
/// </summary>
[Description("Searches the web for a query and returns result snippets.")]
static async Task<string> SearchWebAsync(
    [Description("The search query string")] string query,
    CancellationToken cancellationToken = default)
{
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "ResearchAgent/1.0 (compatible; bot)");

    var encoded = WebUtility.UrlEncode(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    try
    {
        var html = await http.GetStringAsync(url, cancellationToken);
        var results = ParseDuckDuckGoResults(html);

        if (results.Count == 0)
            return $"No results found for: {query}";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: {query}");
        sb.AppendLine();
        foreach (var (title, snippet, link) in results.Take(5))
        {
            sb.AppendLine($"• {title}");
            sb.AppendLine($"  {snippet}");
            if (!string.IsNullOrEmpty(link))
                sb.AppendLine($"  Source: {link}");
            sb.AppendLine();
        }

        return sb.ToString();
    }
    catch (Exception ex)
    {
        return $"Search failed for '{query}': {ex.Message}";
    }
}

static List<(string Title, string Snippet, string Link)> ParseDuckDuckGoResults(string html)
{
    var results = new List<(string, string, string)>();

    // Parse result blocks between "result__a" anchors
    var searchPos = 0;
    while (searchPos < html.Length && results.Count < 8)
    {
        var anchorIdx = html.IndexOf("result__a", searchPos, StringComparison.Ordinal);
        if (anchorIdx < 0) break;

        // Extract title from the anchor tag
        var title = ExtractTextBetween(html, anchorIdx, ">", "</a>");
        var link = ExtractAttribute(html, anchorIdx - 200 < 0 ? 0 : anchorIdx - 200, anchorIdx + 500, "href=\"", "\"");

        // Look for snippet
        var snippetIdx = html.IndexOf("result__snippet", anchorIdx, StringComparison.Ordinal);
        var snippet = snippetIdx > 0
            ? ExtractTextBetween(html, snippetIdx, ">", "</")
            : "";

        if (!string.IsNullOrWhiteSpace(title))
        {
            results.Add((
                WebUtility.HtmlDecode(title).Trim(),
                WebUtility.HtmlDecode(snippet).Trim(),
                link?.Trim() ?? ""));
        }

        searchPos = anchorIdx + 10;
    }

    return results;
}

static string ExtractTextBetween(string html, int startSearch, string startMarker, string endMarker)
{
    var start = html.IndexOf(startMarker, startSearch, StringComparison.Ordinal);
    if (start < 0) return "";
    start += startMarker.Length;

    var end = html.IndexOf(endMarker, start, StringComparison.Ordinal);
    if (end < 0) return "";

    // Strip any inner HTML tags
    var raw = html[start..end];
    return StripHtmlTags(raw);
}

static string? ExtractAttribute(string html, int from, int to, string prefix, string suffix)
{
    var searchRegion = html[from..Math.Min(to, html.Length)];
    var idx = searchRegion.IndexOf(prefix, StringComparison.Ordinal);
    if (idx < 0) return null;
    idx += prefix.Length;
    var end = searchRegion.IndexOf(suffix, idx, StringComparison.Ordinal);
    if (end < 0) return null;
    var value = searchRegion[idx..end];
    return WebUtility.HtmlDecode(value);
}

static string StripHtmlTags(string input)
{
    var sb = new StringBuilder(input.Length);
    var inTag = false;
    foreach (var ch in input)
    {
        if (ch == '<') { inTag = true; continue; }
        if (ch == '>') { inTag = false; continue; }
        if (!inTag) sb.Append(ch);
    }
    return sb.ToString();
}

// --- Notepad tool class ------------------------------------------------------

/// <summary>
/// Simple in-memory note-taking tool for the research agent.
/// </summary>
sealed class Notepad
{
    private readonly List<(string Title, string Body)> _notes = [];

    public int Count => _notes.Count;

    [Description("Adds a research note with a title and body.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string body)
    {
        _notes.Add((title, body));
        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Returns all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"Note #{i + 1}: {_notes[i].Title}");
            sb.AppendLine(_notes[i].Body);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

